// seedNovelStore builds a temp SQLite store with a small two-client fleet:
//
//	Acme Corp  — device DT01 (3 open alerts, healthy storage)
//	             agent acme-dc1: screenshot PASSED, snapshot fresh   -> recoverable
//	             agent acme-sql: screenshot FAILED, snapshot fresh   -> failedScreenshotOnly
//	Globex     — device DT02 (0 open alerts)
//	             agent glob-fs1: screenshot PASSED, snapshot 10d old -> staleOnly
//	             agent glob-old: archived (excluded everywhere)
//
// Returns the db path for --db injection.
func seedNovelStore(t *testing.T) string {
	t.Helper()
	dbPath := filepath.Join(t.TempDir(), "novel-test.db")
	db, err := store.OpenWithContext(context.Background(), dbPath)
	if err != nil {
		t.Fatalf("opening test store: %v", err)
	}
	defer db.Close()

	now := time.Now().Unix()
	fresh := now - 3600     // 1h ago
	stale := now - 10*86400 // 10d ago

	devices := []map[string]any{
		{
			"id": "DT01", "serialNumber": "DT01", "name": "acme-siris",
			"model": "SIRIS 4", "clientCompanyName": "Acme Corp",
			"lastSeenDate":          time.Now().UTC().Format(time.RFC3339),
			"alertCount":            3,
			"localStorageUsed":      map[string]any{"size": 750.0},
			"localStorageAvailable": map[string]any{"size": 250.0},
			"offsiteStorageUsed":    map[string]any{"size": 500.0},
		},
		{
			"id": "DT02", "serialNumber": "DT02", "name": "globex-alto",
			"model": "ALTO 3", "clientCompanyName": "Globex",
			"lastSeenDate":          time.Now().UTC().Format(time.RFC3339),
			"alertCount":            0,
			"localStorageUsed":      map[string]any{"size": 100.0},
			"localStorageAvailable": map[string]any{"size": 900.0},
			"offsiteStorageUsed":    map[string]any{"size": 50.0},
		},
	}
	agents := []map[string]any{
		{
			"id": "acme-dc1", "agentName": "acme-dc1", "os": "Windows Server 2022",
			"deviceSerialNumber": "DT01", "clientCompanyName": "Acme Corp",
			"lastScreenshotAttempt": fresh, "lastScreenshotAttemptStatus": true,
			"lastSnapshot": fresh, "latestOffsite": fresh,
			"isPaused": false, "isArchived": false, "agentVersion": "2.5.0",
		},
		{
			"id": "acme-sql", "agentName": "acme-sql", "os": "Windows Server 2019",
			"deviceSerialNumber": "DT01", "clientCompanyName": "Acme Corp",
			"lastScreenshotAttempt": fresh, "lastScreenshotAttemptStatus": false,
			"lastSnapshot": fresh, "latestOffsite": fresh,
			"isPaused": false, "isArchived": false, "agentVersion": "2.4.0",
		},
		{
			"id": "glob-fs1", "agentName": "glob-fs1", "os": "Ubuntu 22.04",
			"deviceSerialNumber": "DT02", "clientCompanyName": "Globex",
			"lastScreenshotAttempt": stale, "lastScreenshotAttemptStatus": true,
			"lastSnapshot": stale, "latestOffsite": stale,
			"isPaused": false, "isArchived": false, "agentVersion": "2.5.0",
		},
		{
			"id": "glob-old", "agentName": "glob-old", "os": "Windows Server 2012",
			"deviceSerialNumber": "DT02", "clientCompanyName": "Globex",
			"lastScreenshotAttempt": stale, "lastScreenshotAttemptStatus": false,
			"lastSnapshot": stale, "latestOffsite": stale,
			"isPaused": false, "isArchived": true, "agentVersion": "2.1.0",
		},
	}
	for _, d := range devices {
		raw, err := json.Marshal(d)
		if err != nil {
			t.Fatalf("marshaling device fixture: %v", err)
		}
		if err := db.UpsertDevice(raw); err != nil {
			t.Fatalf("seeding device: %v", err)
		}
	}
	for _, a := range agents {
		raw, err := json.Marshal(a)
		if err != nil {
			t.Fatalf("marshaling agent fixture: %v", err)
		}
		if err := db.UpsertAgent(raw); err != nil {
			t.Fatalf("seeding agent: %v", err)
		}
	}
	return dbPath
}

// runNovelCmd executes a novel command constructor against the seeded store
// and returns captured stdout for JSON assertions.
func runNovelCmd(t *testing.T, build func(*rootFlags) *cobra.Command, args ...string) []byte {
	t.Helper()
	flags := &rootFlags{}
	cmd := build(flags)
	var out, errOut bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetErr(&errOut)
	cmd.SetArgs(args)
	if err := cmd.Execute(); err != nil {
		t.Fatalf("command failed: %v (stderr: %s)", err, errOut.String())
	}
	return out.Bytes()
}

// mustUnmarshal decodes command JSON output, failing the test on bad JSON.
func mustUnmarshal(t *testing.T, raw []byte, v any) {
	t.Helper()
	if err := json.Unmarshal(raw, v); err != nil {
		t.Fatalf("invalid JSON output: %v\n%s", err, raw)
	}
}

// fixtureSanity exists so a future schema change in the seed helper fails
// loudly here rather than as a confusing downstream assertion.
func TestNovelFixtureSeeds(t *testing.T) {
	dbPath := seedNovelStore(t)
	db, err := store.OpenWithContext(context.Background(), dbPath)
	if err != nil {
		t.Fatalf("reopening store: %v", err)
	}
	defer db.Close()
	for table, want := range map[string]int{"device": 2, "agent": 4} {
		var n int
		query := fmt.Sprintf(`SELECT COUNT(*) FROM "%s"`, table)
		if err := db.DB().QueryRow(query).Scan(&n); err != nil {
			t.Fatalf("counting %s: %v", table, err)
		}
		if n != want {
			t.Fatalf("seeded %s rows = %d, want %d", table, n, want)
		}
	}
}
